{
  languages.python = {
    enable = true;
    version = "3.12";
    uv = {
      enable = true;
      sync.enable = true;
    };
  };

  dotenv.enable = true;

  # mysqlclient と WeasyPrint のビルドに必要なシステム依存
  packages = [
    # MySQL
    pkgs.libmysqlclient
    pkgs.libmysqlclient.dev
    pkgs.pkg-config
    pkgs.openssl

    # Linter / Formatter / LSP
    pkgs.ruff
    pkgs.basedpyright
  ];

  # mysqlclient ビルド用の環境変数
  env = {
    MYSQLCLIENT_CFLAGS = "-I${pkgs.libmysqlclient.dev}/include/mariadb";
    MYSQLCLIENT_LDFLAGS = "-L${pkgs.libmysqlclient}/lib/mariadb -lmariadb";
  };

  # pre-commit hooks
  pre-commit.hooks = {
    # Ruff linter
    ruff = {
      enable = true;
      settings = {
        configPath = "pyproject.toml";
      };
    };
    # Ruff formatter
    ruff-format = {
      enable = true;
      settings = {
        configPath = "pyproject.toml";
      };
    };
    # Nix formatter
    nixfmt-rfc-style.enable = true;
  };

  # treefmt (nix fmt) 設定
  # Note: devenv 1.4+ で対応
  # treefmt = {
  #   programs.nixfmt.enable = true;
  #   programs.ruff-check.enable = true;
  #   programs.ruff-format.enable = true;
  # };

  enterShell = ''
    echo "🐍 Python $(python --version | cut -d' ' -f2)"
    echo "📦 uv $(uv --version | cut -d' ' -f3)"
    echo "🗄️  mariadb_config: $(which mariadb_config)"
    echo ""
    echo "🔧 Dev tools:"
    echo "   ruff $(ruff --version | head -1)"
    echo "   basedpyright $(basedpyright --version)"
    echo ""
    echo "📝 Commands:"
    echo "   ruff check .        # lint"
    echo "   ruff format .       # format"
    echo "   basedpyright        # type check"
  '';
}

